{
    devices.map((dev: any, idx: number) => (
        <div
            key={dev.id || idx}
            // This is the trigger
            onClick={() => handleDeviceClick(dev)}
            // cursor-pointer is essential for the "hand" icon
            // z-10 ensures it's above the background
            className="relative z-10 bg-white p-6 rounded-3xl shadow-sm border-2 border-transparent hover:border-blue-500 transition-all cursor-pointer group active:scale-95"
        >
            <div className="flex justify-between items-start mb-6">
                <div className="bg-slate-100 p-4 rounded-2xl text-slate-600 group-hover:bg-blue-600 group-hover:text-white transition-all">
                    {/* Your Icon Logic */}
                    <Monitor className="w-8 h-8" />
                </div>
                <div className="px-2 py-1 rounded-lg bg-green-50 text-green-600 text-[10px] font-black uppercase">
                    {dev.state || 'up'}
                </div>
            </div>

            <h3 className="font-black text-slate-900 text-xl mb-1 truncate">
                {dev.device_guess || "Unknown Node"}
            </h3>

            <p className="text-blue-600 font-mono font-bold text-sm">
                {dev.ip4}
            </p>

            {/* Adding a visual "Button" inside the card helps users know it's clickable */}
            <div className="mt-6 pt-6 border-t border-slate-50 flex items-center justify-between pointer-events-none">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Details</span>
                <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-blue-500 group-hover:translate-x-1 transition-all" />
            </div>
        </div>
    ))
}